import{_ as e,c as h,a as n,o as s}from"./app-CEcM0piI.js";const p={};function r(d,a){return s(),h("div",null,a[0]||(a[0]=[n('<p>一组控制和管理计算机硬件和软件资源，合理地对各类作业进行调度以及方便用户使用的程序的集合</p><h1 id="功能" tabindex="-1"><a class="header-anchor" href="#功能"><span>功能</span></a></h1><h2 id="管理资源" tabindex="-1"><a class="header-anchor" href="#管理资源"><span>管理资源</span></a></h2><p>处理机管理 存储器管理 文件管理 设备管理</p><h2 id="向上层提供的服务" tabindex="-1"><a class="header-anchor" href="#向上层提供的服务"><span>向上层提供的服务</span></a></h2><p>GUI用户图形界面 命令接口 程序接口</p><h1 id="特征" tabindex="-1"><a class="header-anchor" href="#特征"><span>特征</span></a></h1><p>并发性 共享性 虚拟性 异步性</p><h1 id="功能-1" tabindex="-1"><a class="header-anchor" href="#功能-1"><span>功能</span></a></h1><h2 id="管理资源-1" tabindex="-1"><a class="header-anchor" href="#管理资源-1"><span>管理资源</span></a></h2><p>处理机管理 存储器管理 文件管理 I/O设备管理</p><h2 id="向上层提供的服务-1" tabindex="-1"><a class="header-anchor" href="#向上层提供的服务-1"><span>向上层提供的服务</span></a></h2><p>GUI用户图形界面 命令接口 程序接口</p><h1 id="特征-1" tabindex="-1"><a class="header-anchor" href="#特征-1"><span>特征</span></a></h1><h3 id="并发" tabindex="-1"><a class="header-anchor" href="#并发"><span>并发</span></a></h3><p>多个事件在同一时刻发生，宏观上是同时发生，微观上是交替发生</p><h3 id="并行" tabindex="-1"><a class="header-anchor" href="#并行"><span>并行</span></a></h3><p>多个事件在同一时刻同时发生</p><h3 id="共享" tabindex="-1"><a class="header-anchor" href="#共享"><span>共享</span></a></h3><p>资源共享，系统中的资源可供内存中多个并发执行的进程共同使用</p><h4 id="互斥共享方式" tabindex="-1"><a class="header-anchor" href="#互斥共享方式"><span>互斥共享方式</span></a></h4><p>当一个资源被一个进程占用时，其他进程想要使用该资源就只给你等待，当前进程使用完资源后才可使用这种资源也叫临界资源或独占资源（如打印机）</p><h4 id="同时共享方式" tabindex="-1"><a class="header-anchor" href="#同时共享方式"><span>同时共享方式</span></a></h4><p>某一资源在一段时间内可由多个进程同时访问（宏观）微观上可能是交替访问（如磁盘）</p><h3 id="虚拟" tabindex="-1"><a class="header-anchor" href="#虚拟"><span>虚拟</span></a></h3><p>把一个物理的实体映射为若干个逻辑的对应物，物理实体是实际存在的而逻辑上对应物是用户感受到的</p><h4 id="时分复用技术" tabindex="-1"><a class="header-anchor" href="#时分复用技术"><span>时分复用技术</span></a></h4><p>微观上处理经常在各个微小的时间段内交替服务各个进程 （一个cpu可以执行多个程序，给用户一种多核的假象）</p><h4 id="空分复用技术" tabindex="-1"><a class="header-anchor" href="#空分复用技术"><span>空分复用技术</span></a></h4><p>多个程序或用户同时使用一个资源的不同部分 （硬盘分为C、D、E盘但实际上知识虚拟逻辑的分区，电脑硬盘只有一个）</p><h3 id="异步" tabindex="-1"><a class="header-anchor" href="#异步"><span>异步</span></a></h3><p>在多道程序环境下，允许多个程序并发执行，但由于资源有限，进程的执行不是一贯到底而是走走停停，交替进行</p><p>并发和共性两者互为存在条件</p><h1 id="_1、无操作系统" tabindex="-1"><a class="header-anchor" href="#_1、无操作系统"><span>1、无操作系统</span></a></h1><p>人工操作输入输出</p><h1 id="_2、单道批处理系统" tabindex="-1"><a class="header-anchor" href="#_2、单道批处理系统"><span>2、单道批处理系统</span></a></h1><p>操作人员把一批作业脱机方式输入到磁带上监督程序运行，内存中只有一道程序能运行</p><h1 id="_3、多道批处理系统" tabindex="-1"><a class="header-anchor" href="#_3、多道批处理系统"><span>3、多道批处理系统</span></a></h1><p>每次往内存中输入多道程序，引入了中断技术，由操作系统管理这些程序的运行，各个进程并发执行 操作系统正式诞生</p><h1 id="_4、分时系统" tabindex="-1"><a class="header-anchor" href="#_4、分时系统"><span>4、分时系统</span></a></h1><p>以时间片为单位轮流为各个作业服务</p><h1 id="_5、实时系统" tabindex="-1"><a class="header-anchor" href="#_5、实时系统"><span>5、实时系统</span></a></h1><p>和分时系统一样，但能优先响应紧急任务</p><h1 id="_6、网络操作系统" tabindex="-1"><a class="header-anchor" href="#_6、网络操作系统"><span>6、网络操作系统</span></a></h1><h1 id="_7、分布式操作系统" tabindex="-1"><a class="header-anchor" href="#_7、分布式操作系统"><span>7、分布式操作系统</span></a></h1><h1 id="_8、嵌入式操作系统" tabindex="-1"><a class="header-anchor" href="#_8、嵌入式操作系统"><span>8、嵌入式操作系统</span></a></h1><h2 id="中断和异常" tabindex="-1"><a class="header-anchor" href="#中断和异常"><span>中断和异常</span></a></h2><h3 id="内中断" tabindex="-1"><a class="header-anchor" href="#内中断"><span>内中断</span></a></h3><p>自愿中断：指令中断 强迫中断：硬件故障，软件中断</p><h3 id="外中断" tabindex="-1"><a class="header-anchor" href="#外中断"><span>外中断</span></a></h3><p>IO请求 人工干预</p>',51)]))}const c=e(p,[["render",r]]),t=JSON.parse('{"path":"/base/os/1/","title":"1 操作系统概述","lang":"zh-CN","frontmatter":{"title":"1 操作系统概述","createTime":"2025/06/22 10:49:22","permalink":"/base/os/1/"},"readingTime":{"minutes":2.63,"words":789},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/操作系统/1 操作系统概述.md","headers":[]}');export{c as comp,t as data};
